code.C:
#include <stdio.h>
#include <math.h>
int main() {
    int a, b, c, d;
    scanf("%d %d %d %d", &a, &b, &c, &d);
    double dist1 = sqrt(pow(a - c, 2) + pow(b - d, 2));
    double dist2 = sqrt(pow(a - d, 2) + pow(b - c, 2));
    printf("%.9f\n", (dist1 < dist2) ? dist1 : dist2);
    return 0;
}

