#include <iostream>
#include <cmath>
using namespace std;
int main() {
    int a, b, c, d;
    cin >> a >> b >> c >> d;
    double dist1 = sqrt(pow(a - c, 2) + pow(b - d, 2));
    double dist2 = sqrt(pow(a - d, 2) + pow(b - c, 2));
    cout << min(dist1, dist2) << endl;
    return 0;
}

