const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
rl.on('line', (input) => {
    const [a, b, c, d] = input.split(' ').map(Number);
    const dist1 = Math.sqrt((a - c) ** 2 + (b - d) ** 2);
    const dist2 = Math.sqrt((a - d) ** 2 + (b - c) ** 2);
    console.log(Math.min(dist1, dist2));
